use managers\AdminsManager;
use managers\SessionManager;

if (isset($_COOKIE['session_id'])) {
    if (is_numeric($_COOKIE['session_id'])) {
        $login = new SessionManager()->getLoginById((int)$_COOKIE['session_id']);
        if ($login === false) {
            not_authorized();
        }
    }else not_authorized();
}else not_authorized();
$role = new AdminsManager()->getRole($login);
function not_authorized(): never {
    setcookie('session_id', '', time() - 3600, '/', '', true, true);
    setcookie('login', '', time() - 3600, '/', '', true, true);
    header('Location: auth.php');
    exit;
}
